import "./App.css";
import LoginButton from "./Components/Login/LoginButton";

import Home from "./Components/Home/Home";
import { useAuth0 } from "@auth0/auth0-react";

function App() {
  const { isAuthenticated } = useAuth0();
  if (isAuthenticated) {
    <Home />;
  } else {
    return (
      <div className="App">
        <LoginButton />
      </div>
    );
  }
}

export default App;
